INSERT INTO `lkp_projects` (`proj_id`, `proj_org_id`, `proj_creator`, `proj_loc_depth`, `proj_name`, `proj_description`, `proj_banner`, `proj_start_date`, `proj_end_date`, `proj_reg_date`, `ip_address`, `status`) VALUES
(1, 2, 1, 1, 'TAAT: High Iron Bean Compact', 'The Technologies for African Agricultural Transformation (TAAT) program is funded by the African Development Bank (AfDB) and other agencies. The aquaculture compact is one of 15 compacts comprising TAAT led by WorldFish.\r\n\r\nTen countries were selected for the TAAT Aquaculture Compact (TAC): the Democratic Republic of Congo, Ghana, Kenya, Nigeria and Zambia as focal countries, and the Republic of Benin, Burundi, Cameroun, Cote dâIvoire and Tanzania as satellite countries. TAC aims to reach out to 1.15 million aquaculture value chain actors in these 10 countries within three years. This will include disseminating and upscaling aquaculture technologies across Africa to increase the productivity and income of fish farmers, increase fish protein consumption and enhance sustainability across the aquaculture value chain.', 'default.png', '2020-07-04 00:00:00', '2021-07-03 00:00:00', '2020-07-04 00:00:00', '127.0.0.1', 1),
(2, 1, 1, 5, 'RECL', 'RECL', 'default.png', '2020-07-04 00:00:00', '2021-07-03 00:00:00', '2020-07-04 00:00:00', '127.0.0.1', 1),
(3, 1, 1, 1, 'ICRISAT Operations', 'To capture the details of the daily ICRISAT operations', 'default.png', '2020-05-29 06:51:16', NULL, '2020-05-29 06:51:16', '183.83.136.107', 1);
